package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.JsonElement;
import com.google.gson.JsonArray;

class JsonElementTest {

  // Subclass of JsonElement for testing non-JsonArray instance
  private static class JsonElementStub extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void testIsJsonArray_whenInstanceIsJsonArray() {
    JsonElement jsonArray = new JsonArray();
    assertTrue(jsonArray.isJsonArray());
  }

  @Test
  void testIsJsonArray_whenInstanceIsNotJsonArray() {
    JsonElement jsonElement = new JsonElementStub();
    assertFalse(jsonElement.isJsonArray());
  }
}
